#!/usr/bin/env python3
"""Fetch instructkr/claude-code repo contents via GitHub API"""
import os
import base64
import json
import urllib.request

def gh_api(path):
    url = f"https://api.github.com/repos/instructkr/claude-code/contents/{path}"
    req = urllib.request.Request(url)
    req.add_header("Accept", "application/vnd.github.v3+json")
    with urllib.request.urlopen(req, timeout=30) as r:
        return json.loads(r.read())

def save_file(content_b64, path):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "wb") as f:
        f.write(base64.b64decode(content_b64))
    print(f"  ✓ {path}")

def process(items, prefix=""):
    for item in items:
        path = prefix + item["name"]
        if item["type"] == "file":
            try:
                content = gh_api(path)
                save_file(content["content"], path)
            except Exception as e:
                print(f"  ✗ {path}: {e}")
        elif item["type"] == "dir":
            print(f"  [dir] {path}/")
            sub = gh_api(path)
            process(sub, path + "/")

base = os.path.dirname(os.path.abspath(__file__))
os.chdir(base)

# Fetch top-level
print("Fetching top-level...")
items = gh_api("")
for item in items:
    if item["name"] == ".gitignore":
        content = gh_api(".gitignore")
        save_file(content["content"], ".gitignore")
    elif item["name"] in ("README.md",):
        content = gh_api(item["name"])
        save_file(content["content"], item["name"])
    elif item["name"] in ("src", "tests", "assets"):
        print(f"  [dir] {item['name']}/")
        process(gh_api(item["name"]), item["name"] + "/")

print("\nDone!")

